const fs = require('fs');

const logPath = '/home/node/.n8n-files/applications_log.csv';
const date = new Date().toISOString().split('T')[0];
const company = $('Edit Fields').first().json['Company Name'];
const jobTitle = $('Edit Fields').first().json['Job Title'];
const language = $('Edit Fields').first().json['Language'];

const analysisText = $('Analyse Resume EN').first().json.text;

// Match patterns like "42%" or "42 %" near "before/after"
const lines = analysisText.split('\n');
let atsBefore = 'N/A';
let atsAfter = 'N/A';

for (const line of lines) {
    const num = line.match(/:\s*(\d+)\s*%/);
    if (!num) continue;
    if (/before/i.test(line)) atsBefore = num[1];
    if (/after/i.test(line)) atsAfter = num[1];
}

const row = `${date},"${company}","${jobTitle}","${language}",${atsBefore},${atsAfter}\n`;

if (!fs.existsSync(logPath)) {
    fs.writeFileSync(logPath, 'Date,Company,Job Title,Language,ATS Before,ATS After\n');
}

fs.appendFileSync(logPath, row);

return [{ json: { logged: true, row: row.trim() } }];

